import { IMessageComposer } from '@nitrots/nitro-renderer';

/**
 * Tells the server the user is leaving / closing the slot machine UI.
 */
export class SlotMachineLeaveComposer implements IMessageComposer<number[]> {
    private _data: number[];

    // Optional: tableId if you support multiple slot machines. Default 0.
    constructor(tableId: number = 0) {
        this._data = [tableId];
    }

    public getMessageArray(): number[] {
        return this._data;
    }

    public dispose(): void {
        // no-op
    }
}
